INSERT INTO public.portfolio_sources (stable_key, source_type, file_name, page_url, title, description, public_source) VALUES ('src_me_md', 'document', 'me.md', 'index.html', 'CV Markdown Complet', 'Profil professionnel et portfolio consolidé.', true) ON CONFLICT (stable_key) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.portfolio_projects (slug, name_fr, name_en, short_summary_fr, short_summary_en, detailed_summary_fr, detailed_summary_en, my_role_fr, my_role_en, project_type, organization, location, tools, skills, key_results, page_url, featured, display_order, verified, source_file) VALUES ('pv-bess-djibouti-dakhla', 'Centrale PV 30 MWc + BESS 5 MWh & 580 kWc', '30 MWp PV + 5 MWh BESS & 580 kWp Plants', 'Études de faisabilité technico-économiques pour des projets solaires à grande échelle.', 'Techno-economic feasibility studies for utility-scale solar projects.', 'Conception électrique complète (SLD, plans d''implantation) couvrant tout le cycle de vie du projet, du dimensionnement à l''intégration au réseau pour un projet de 30 MWc à Djibouti et deux de 580 kWc à Dakhla.', 'Complete electrical design (SLD, layout plans) covering the entire project lifecycle, from sizing to grid integration for a 30 MWp project in Djibouti and two 580 kWp projects in Dakhla.', 'Conception de bout en bout, simulations et modélisation', 'End-to-end design, simulations and modeling', 'Utility-scale Solar + BESS', 'Novec', 'Djibouti / Dakhla, Maroc', ARRAY['PVSyst','Caneco BT','HOMER Pro','PowerFactory','AutoCAD']::text[], ARRAY['Études technico-économiques','Conception électrique','SLD','Intégration au réseau']::text[], '[]'::jsonb, 'solar-project.html', true, 1, true, 'me.md') ON CONFLICT (slug) DO UPDATE SET name_fr = EXCLUDED.name_fr;
INSERT INTO public.portfolio_projects (slug, name_fr, name_en, short_summary_fr, short_summary_en, detailed_summary_fr, detailed_summary_en, my_role_fr, my_role_en, project_type, organization, location, tools, skills, key_results, page_url, featured, display_order, verified, source_file) VALUES ('pv-bess-67mw-ems', 'Centrale PV 67 MW + BESS (Modélisation EMS/BMS)', '67 MW PV + BESS (EMS/BMS Modeling)', 'Dimensionnement et étude technico-économique d''une centrale de 67 MW avec BESS.', 'Sizing and techno-economic study of a 67 MW solar plant with BESS.', 'Conception et modélisation de la logique EMS (Energy Management System) et BMS dans MATLAB/Simulink, simulant le contrôle en temps réel et la stabilité du réseau.', 'Design and modeling of EMS and BMS logic in MATLAB/Simulink, simulating real-time control and grid stability.', 'Conception de l''architecture EMS et simulation dynamique', 'EMS architecture design and dynamic simulation', 'Dynamic Simulation & Control', 'Université Internationale de Rabat (UIR)', 'Maroc', ARRAY['PVSyst','MATLAB','Simulink']::text[], ARRAY['Dimensionnement BESS','Logique EMS','BMS','Stabilité du réseau','Simulation RMS']::text[], '[]'::jsonb, 'solar-bess-67mw.html', true, 2, true, 'me.md') ON CONFLICT (slug) DO UPDATE SET name_fr = EXCLUDED.name_fr;
INSERT INTO public.portfolio_projects (slug, name_fr, name_en, short_summary_fr, short_summary_en, detailed_summary_fr, detailed_summary_en, my_role_fr, my_role_en, project_type, organization, location, tools, skills, key_results, page_url, featured, display_order, verified, source_file) VALUES ('ibwatts', 'Application Web Technico-Économique Solaire (IBWatts)', 'Solar Techno-Economic Web App (IBWatts)', 'Application Web avancée d''analyse technico-économique solaire pour le marché marocain.', 'Advanced web application for solar techno-economic analysis in the Moroccan market.', 'Intègre une base de données d''équipements réels (panneaux, onduleurs, batteries), analyse des ombrages, dimensionnement automatique. Moteur financier simulant prêts, ROI, VAN et amortissement (ONE/Régies) avec génération PDF.', 'Integrates a real equipment database, shading analysis, and auto-sizing. Financial engine simulates loans, ROI, NPV, and payback periods (ONE/Régies tariffs) with automatic PDF generation.', 'Développeur full-stack et concepteur du moteur financier', 'Full-stack developer and financial engine architect', 'Software Engineering', NULL, 'Maroc', ARRAY['Python','Streamlit','Pandas','NumPy','Matplotlib']::text[], ARRAY['Développement Web','Moteur Financier','LCOE','ROI','VAN']::text[], '[{"metric": "Fonctionnalit\u00e9", "value": "Base de donn\u00e9es d''\u00e9quipements locaux"}]'::jsonb, 'ibwatts.html', true, 3, true, 'me.md') ON CONFLICT (slug) DO UPDATE SET name_fr = EXCLUDED.name_fr;
INSERT INTO public.portfolio_projects (slug, name_fr, name_en, short_summary_fr, short_summary_en, detailed_summary_fr, detailed_summary_en, my_role_fr, my_role_en, project_type, organization, location, tools, skills, key_results, page_url, featured, display_order, verified, source_file) VALUES ('smart-house', 'Maison Bioclimatique Intelligente & Stockage Thermique', 'Smart Bioclimatic House & Thermal Storage', 'Modélisation d''une maison à haute efficacité et stockage thermique intersaisonnier.', 'Modeling a high-efficiency house with interseasonal thermal storage.', 'Conception d''un système de stockage thermique à base de sable. Prototype matériel d''un système de contrôle climatique automatisé (Arduino R4, capteurs DHT22, logique PID) pour optimiser le confort thermique.', 'Design of a sand-based thermal storage system. Hardware prototyping of an automated climate control system (Arduino R4, DHT22 sensors, PID logic) for optimal thermal comfort.', 'Conception thermique et réalisation du prototype IoT', 'Thermal design and IoT prototype development', 'Thermal Engineering & IoT', NULL, 'Rabat/Casablanca, Maroc', ARRAY['DesignBuilder','Arduino','Python']::text[], ARRAY['Stockage Thermique','Logique PID','Réglementation Thermique (RTCM)','IoT']::text[], '[]'::jsonb, 'smart_house.html', true, 4, true, 'me.md') ON CONFLICT (slug) DO UPDATE SET name_fr = EXCLUDED.name_fr;
INSERT INTO public.portfolio_projects (slug, name_fr, name_en, short_summary_fr, short_summary_en, detailed_summary_fr, detailed_summary_en, my_role_fr, my_role_en, project_type, organization, location, tools, skills, key_results, page_url, featured, display_order, verified, source_file) VALUES ('hydrotwin', 'Jumeau Numérique Hydrogène Vert (Power-to-X)', 'Green Hydrogen Digital Twin (Power-to-X)', 'Modélisation Python de la chaîne PV → Électrolyseur PEM → LOHC.', 'Python modeling of the PV → PEM Electrolyzer → LOHC chain.', 'Développement d''un moteur physique sur mesure en Python pour optimiser le LCOH (coût actualisé de l''hydrogène) sous des contraintes de réseau et d''irradiation marocaines.', 'Development of a custom physical engine in Python to optimize LCOH (Levelized Cost of Hydrogen) under Moroccan grid and irradiation constraints.', 'Conception du modèle physique et optimisation algorithmique', 'Physical model design and algorithmic optimization', 'Energy Modeling', NULL, 'Maroc', ARRAY['Python','NumPy','Pandas']::text[], ARRAY['Power-to-X','Hydrogène Vert','LCOH','LOHC','Électrolyseur PEM']::text[], '[]'::jsonb, 'hydrotwin.html', true, 5, true, 'me.md') ON CONFLICT (slug) DO UPDATE SET name_fr = EXCLUDED.name_fr;
INSERT INTO public.portfolio_projects (slug, name_fr, name_en, short_summary_fr, short_summary_en, detailed_summary_fr, detailed_summary_en, my_role_fr, my_role_en, project_type, organization, location, tools, skills, key_results, page_url, featured, display_order, verified, source_file) VALUES ('hospital-audit', 'Audit Énergétique Hybride — Hôpital', 'Hybrid Energy Audit — Hospital', 'Audit d''un hôpital et conception d''un système hybride (Solaire + Éolien + Réseau).', 'Hospital audit and hybrid system design (Solar + Wind + Grid).', 'Réduction des coûts énergétiques annuels de 18 % tout en maintenant la fiabilité critique.', 'Reduction of annual energy costs by 18% while maintaining critical reliability.', 'Auditeur énergétique', 'Energy Auditor', 'Energy Audit', NULL, 'Maroc', ARRAY['HOMER Pro']::text[], ARRAY['Audit Énergétique','Systèmes Hybrides']::text[], '[{"metric": "R\u00e9duction des co\u00fbts", "value": "18 %"}]'::jsonb, 'index.html', false, 6, true, 'me.md') ON CONFLICT (slug) DO UPDATE SET name_fr = EXCLUDED.name_fr;
INSERT INTO public.portfolio_projects (slug, name_fr, name_en, short_summary_fr, short_summary_en, detailed_summary_fr, detailed_summary_en, my_role_fr, my_role_en, project_type, organization, location, tools, skills, key_results, page_url, featured, display_order, verified, source_file) VALUES ('ai-prediction', 'Système de Prédiction Énergétique par IA', 'AI Energy Prediction System', 'Prédicteur de consommation basé sur le Machine Learning.', 'Consumption predictor based on Machine Learning.', 'Utilise la température, l''humidité et la date pour prévoir la consommation avec une précision de 92 %.', 'Uses temperature, humidity, and date to forecast consumption with 92% accuracy.', 'Développeur Machine Learning', 'Machine Learning Developer', 'Artificial Intelligence', NULL, 'Maroc', ARRAY['Python']::text[], ARRAY['Machine Learning','Prédiction']::text[], '[{"metric": "Pr\u00e9cision", "value": "92 %"}]'::jsonb, 'ai-prediction.html', false, 7, true, 'me.md') ON CONFLICT (slug) DO UPDATE SET name_fr = EXCLUDED.name_fr;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('profile.professional_summary.fr', NULL, 'fr', 'professional_summary', 'identity', 'Résumé Professionnel', 'Ibrahim Khallouq est un Ingénieur en Énergétique et Énergies Renouvelables diplômé de l''UIR. Il maîtrise l''ensemble du domaine énergétique : systèmes thermiques, électriques, renouvelables, conventionnels, et technologies émergentes comme l''hydrogène vert et le stockage (BESS). Il est capable de gérer un projet de A à Z : étude de faisabilité, conception, simulation, optimisation, et audit.', ARRAY['Ingénieur','Énergies Renouvelables','BESS','Hydrogène','Thermique']::text[], ARRAY['Étude technico-économique','Conception','Simulation numérique','Audit énergétique']::text[], ARRAY[]::text[], ARRAY['Qui est Ibrahim Khallouq ?','Quel est le profil d''Ibrahim ?']::text[], 'index.html', 'Profil (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('profile.professional_summary.en', NULL, 'en', 'professional_summary', 'identity', 'Professional Summary', 'Ibrahim Khallouq is an Energy and Renewable Energies Engineer graduated from UIR. He masters the entire energy field: thermal, electrical, renewable, conventional systems, and emerging technologies like green hydrogen and storage (BESS). He can manage a project from A to Z: feasibility study, design, simulation, optimization, and energy audit.', ARRAY['Engineer','Renewable Energy','BESS','Hydrogen','Thermal']::text[], ARRAY['Techno-economic study','Design','Numerical simulation','Energy audit']::text[], ARRAY[]::text[], ARRAY['Who is Ibrahim Khallouq?','What is Ibrahim''s profile?']::text[], 'index.html', 'Profile (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('profile.education.fr', NULL, 'fr', 'education', 'education', 'Formation d''Ibrahim', 'Ibrahim a obtenu son Diplôme d''Ingénieur en Énergétique & Énergies Renouvelables à l''Université Internationale de Rabat (UIR) (2021–2026). Ses modules clés incluent la Thermodynamique, Mécanique des Fluides (CFD), Électrotechnique, Smart Grids, et l''Audit Énergétique.', ARRAY['UIR','Diplôme','Université Internationale de Rabat']::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['Quelle est la formation d''Ibrahim ?','Où Ibrahim a-t-il étudié ?']::text[], 'index.html', 'Education (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('experience.novec.responsibilities.fr', (SELECT id FROM public.portfolio_projects WHERE slug = 'pv-bess-djibouti-dakhla'), 'fr', 'experience_responsibility', 'experience', 'Expérience chez Novec', 'Ibrahim a travaillé comme Ingénieur Projet Énergie chez Novec (Bureau d''Études) en 2026. Il a mené les études de faisabilité complètes, la conception de bout en bout (SLD) et les simulations pour une centrale PV de 30 MWc avec BESS à Djibouti, et deux centrales de 580 kWc à Dakhla.', ARRAY['Novec','Djibouti','Dakhla','Bureau d''Études']::text[], ARRAY['Études de faisabilité','SLD','Dimensionnement']::text[], ARRAY['PVSyst','HOMER Pro','Caneco BT','PowerFactory']::text[], ARRAY['Où Ibrahim a-t-il travaillé en 2026 ?','Quelle est son expérience chez Novec ?']::text[], 'solar-project.html', 'Experience (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('experience.novec.responsibilities.en', (SELECT id FROM public.portfolio_projects WHERE slug = 'pv-bess-djibouti-dakhla'), 'en', 'experience_responsibility', 'experience', 'Experience at Novec', 'Ibrahim worked as an Energy Project Engineer at Novec (Consulting Firm) in 2026. He led full feasibility studies, end-to-end electrical design (SLD), and simulations for a 30 MWp PV plant with BESS in Djibouti, and two 580 kWp plants in Dakhla.', ARRAY['Novec','Djibouti','Dakhla','Consulting']::text[], ARRAY['Feasibility studies','SLD','Sizing']::text[], ARRAY['PVSyst','HOMER Pro','Caneco BT','PowerFactory']::text[], ARRAY['Where did Ibrahim work in 2026?','What is his experience at Novec?','Has Ibrahim worked on utility-scale solar?']::text[], 'solar-project.html', 'Experience (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('profile.powerfactory_skill.fr', NULL, 'fr', 'software_skill', 'software', 'Compétences PowerFactory (DIgSILENT)', 'Ibrahim utilise PowerFactory (DIgSILENT) pour la simulation de réseaux électriques et l''intégration de centrales solaires au réseau (simulations RMS, conception de SLD, validation dynamique).', ARRAY['PowerFactory','DIgSILENT','Réseaux électriques','RMS']::text[], ARRAY['Simulation de réseaux','Intégration réseau']::text[], ARRAY['PowerFactory']::text[], ARRAY['Quels projets utilisent PowerFactory ?','Ibrahim maîtrise-t-il PowerFactory ?']::text[], 'index.html', 'Skills (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('profile.powerfactory_skill.en', NULL, 'en', 'software_skill', 'software', 'PowerFactory (DIgSILENT) Skills', 'Ibrahim uses PowerFactory (DIgSILENT) for electrical grid simulations and solar plant grid integration (RMS simulations, SLD design, dynamic validation).', ARRAY['PowerFactory','DIgSILENT','Electrical grids','RMS']::text[], ARRAY['Grid simulation','Grid integration']::text[], ARRAY['PowerFactory']::text[], ARRAY['Which projects use PowerFactory?','Does Ibrahim know PowerFactory?']::text[], 'index.html', 'Skills (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('profile.python_skill.fr', NULL, 'fr', 'software_skill', 'python', 'Compétences en Python', 'Ibrahim a un niveau avancé en Python. Il utilise Pandas, NumPy et Matplotlib pour l''analyse de données, le Machine Learning (prédiction avec 92% de précision), la modélisation physique (moteur LCOH pour l''hydrogène vert) et Streamlit pour développer des applications web technico-économiques comme IBWatts.', ARRAY['Python','Pandas','Streamlit','Machine Learning']::text[], ARRAY['Développement Web','Analyse de données']::text[], ARRAY['Python','Streamlit']::text[], ARRAY['Quel projet démontre ses compétences en Python ?','Ibrahim code-t-il en Python ?']::text[], 'ibwatts.html', 'Skills (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('profile.python_skill.en', NULL, 'en', 'software_skill', 'python', 'Python Skills', 'Ibrahim has an advanced level in Python. He uses Pandas, NumPy, and Matplotlib for data analysis, Machine Learning (forecasting with 92% accuracy), physical modeling (LCOH engine for green hydrogen), and Streamlit to develop techno-economic web apps like IBWatts.', ARRAY['Python','Pandas','Streamlit','Machine Learning']::text[], ARRAY['Web Development','Data Analysis']::text[], ARRAY['Python','Streamlit']::text[], ARRAY['Which project demonstrates his Python skills?','Does Ibrahim code in Python?']::text[], 'ibwatts.html', 'Skills (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('profile.bess_skill.fr', NULL, 'fr', 'technical_skill', 'bess', 'Expérience avec les BESS', 'Ibrahim possède une vaste expérience avec les systèmes de stockage d''énergie par batterie (BESS). Il a dimensionné un BESS de 5 MWh pour Djibouti, intégré des BESS pour des projets de 580 kWc à Dakhla, et modélisé la logique EMS/BMS pour une centrale couplée de 67 MW sur MATLAB/Simulink.', ARRAY['BESS','Stockage','Batterie','EMS','BMS']::text[], ARRAY['Dimensionnement','Modélisation','BMS']::text[], ARRAY['MATLAB','Simulink','PVSyst']::text[], ARRAY['Quelle expérience Ibrahim a-t-il avec les BESS ?','A-t-il travaillé sur le stockage par batterie ?']::text[], 'solar-bess-67mw.html', 'Skills (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('profile.bess_skill.en', NULL, 'en', 'technical_skill', 'bess', 'Experience with BESS', 'Ibrahim has extensive experience with Battery Energy Storage Systems (BESS). He sized a 5 MWh BESS for Djibouti, integrated BESS for 580 kWp projects in Dakhla, and modeled EMS/BMS logic for a 67 MW coupled plant using MATLAB/Simulink.', ARRAY['BESS','Storage','Battery','EMS','BMS']::text[], ARRAY['Sizing','Modeling','BMS']::text[], ARRAY['MATLAB','Simulink','PVSyst']::text[], ARRAY['What experience does Ibrahim have with BESS?','Has he worked on battery storage?']::text[], 'solar-bess-67mw.html', 'Skills (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('project.ibwatts.financial_engine.fr', (SELECT id FROM public.portfolio_projects WHERE slug = 'ibwatts'), 'fr', 'engineering_result', 'financial_analysis', 'Moteur Financier d''IBWatts', 'Pour l''application IBWatts, Ibrahim a développé un moteur financier complet. Il permet de simuler les prêts bancaires, de calculer le retour sur investissement (ROI), la valeur actuelle nette (VAN) et le délai d''amortissement en se basant sur les tarifs locaux marocains (ONE/Régies), avec génération de PDF automatiques.', ARRAY['Finance','ROI','VAN','Tarifs locaux','Streamlit','IBWatts']::text[], ARRAY['Analyse financière','Développement Python']::text[], ARRAY['Python','Streamlit']::text[], ARRAY['Comment fonctionne IBWatts ?','Ibrahim sait-il faire de l''analyse financière ?']::text[], 'ibwatts.html', 'IBWatts Project (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('project.67mw.ems.fr', (SELECT id FROM public.portfolio_projects WHERE slug = 'pv-bess-67mw-ems'), 'fr', 'control_logic', 'ems', 'Développement EMS pour centrale 67 MW', 'Ibrahim a conçu et modélisé la logique d''un système de gestion de l''énergie (EMS) et d''un BMS pour une centrale photovoltaïque de 67 MW couplée à un BESS. Il a utilisé MATLAB/Simulink pour simuler le contrôle en temps réel et assurer la stabilité du réseau électrique.', ARRAY['EMS','BMS','MATLAB','Simulink','Contrôle en temps réel']::text[], ARRAY['Modélisation','Contrôle']::text[], ARRAY['MATLAB','Simulink']::text[], ARRAY['Ibrahim a-t-il développé un EMS ?','Qu''a fait Ibrahim sur la centrale 67 MW ?']::text[], 'solar-bess-67mw.html', '67MW Project (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('project.67mw.ems.en', (SELECT id FROM public.portfolio_projects WHERE slug = 'pv-bess-67mw-ems'), 'en', 'control_logic', 'ems', 'EMS Development for 67 MW Plant', 'Ibrahim designed and modeled the logic for an Energy Management System (EMS) and BMS for a 67 MW PV plant coupled with a BESS. He used MATLAB/Simulink to simulate real-time control and ensure power grid stability.', ARRAY['EMS','BMS','MATLAB','Simulink','Real-time control']::text[], ARRAY['Modeling','Control']::text[], ARRAY['MATLAB','Simulink']::text[], ARRAY['Did Ibrahim develop an EMS?','What did Ibrahim do on the 67 MW plant?']::text[], 'solar-bess-67mw.html', '67MW Project (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('project.smart_house.energy_results.fr', (SELECT id FROM public.portfolio_projects WHERE slug = 'smart-house'), 'fr', 'engineering_result', 'thermal_engineering', 'Résultats de la Maison Bioclimatique (Smart House)', 'Dans le cadre du projet de maison bioclimatique intelligente, Ibrahim a conçu un système de stockage thermique intersaisonnier à base de sable. Il a aussi prototypé un système de contrôle automatisé matériel (Arduino R4, capteurs DHT22, PID) pour réguler le confort thermique.', ARRAY['Stockage thermique','Sable','Arduino','IoT','PID']::text[], ARRAY['Thermique du bâtiment','IoT','Régulation PID']::text[], ARRAY['DesignBuilder','Arduino','Python']::text[], ARRAY['Quels sont les résultats de la maison intelligente ?','Ibrahim a-t-il fait de l''IoT ?']::text[], 'smart_house.html', 'Smart House (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('project.smart_house.energy_results.en', (SELECT id FROM public.portfolio_projects WHERE slug = 'smart-house'), 'en', 'engineering_result', 'thermal_engineering', 'Smart House Results', 'As part of the smart bioclimatic house project, Ibrahim designed an interseasonal sand-based thermal storage system. He also prototyped an automated hardware climate control system (Arduino R4, DHT22 sensors, PID) to regulate thermal comfort.', ARRAY['Thermal storage','Sand','Arduino','IoT','PID']::text[], ARRAY['Building thermal engineering','IoT','PID control']::text[], ARRAY['DesignBuilder','Arduino','Python']::text[], ARRAY['What are the Smart House results?','Did Ibrahim work with IoT?']::text[], 'smart_house.html', 'Smart House (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('project.hydrotwin.lcoh_optimization.fr', (SELECT id FROM public.portfolio_projects WHERE slug = 'hydrotwin'), 'fr', 'engineering_result', 'hydrogen', 'Optimisation LCOH - HydroTwin', 'Pour le jumeau numérique Power-to-X (HydroTwin), Ibrahim a développé un moteur physique sur mesure en Python. Le résultat principal a été l''optimisation du LCOH (Levelized Cost of Hydrogen) en prenant en compte l''irradiation marocaine et les contraintes de réseau pour la chaîne PV - Électrolyseur - LOHC.', ARRAY['LCOH','LOHC','Hydrogène','Power-to-X','Optimisation']::text[], ARRAY['Modélisation hydrogène','Analyse LCOH']::text[], ARRAY['Python']::text[], ARRAY['Comment le LCOH a-t-il été optimisé ?','Qu''est-ce que le projet HydroTwin ?']::text[], 'hydrotwin.html', 'HydroTwin (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
INSERT INTO public.portfolio_knowledge_items (stable_key, project_id, language, content_type, category, title, content, keywords, skills, tools, question_variants, source_url, source_label, source_file, verified, approved_for_ai, is_public, metadata) VALUES ('contact.info.fr', NULL, 'fr', 'contact', 'contact', 'Coordonnées', 'Vous pouvez contacter Ibrahim Khallouq par téléphone au +212 650 93 18 50 ou par email à khallouk.ibrahim@uir.ac.ma. Son LinkedIn est linkedin.com/in/ibrahim-khallouq.', ARRAY['Contact','Email','Téléphone','LinkedIn']::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['Comment contacter Ibrahim ?','Quel est son email ?']::text[], 'index.html', 'Contact (me.md)', 'me.md', true, true, true, '{"contribution_scope": "individual"}'::jsonb) ON CONFLICT (stable_key) DO UPDATE SET content = EXCLUDED.content;
